/**
 * Secure query builder that uses parameterized queries to prevent SQL injection.
 * 
 * WARNING: Never use raw string interpolation (s"..." or f"...") to build SQL queries
 * with user input. Always use Slick's sql"..." interpolation which properly parameterizes values,
 * or build queries using the approach below with explicit parameter binding.
 */
class SecureProductQueryBuilder {

  /**
   * Builds a safe parameterized query using Slick's sql interpolator.
   * Each filter condition uses bound parameters, never string concatenation.
   */
  def buildSearchQuery(params: Map[String, Seq[String]]): SQLActionBuilder = {
    import slick.jdbc.MySQLProfile.api._

    val baseQuery = sql"SELECT id, name, description, category, price, in_stock FROM products WHERE 1=1"

    var query = baseQuery

    params.get("name").flatMap(_.headOption).foreach { name =>
      query = concat(query, sql" AND LOWER(name) LIKE LOWER(${s"%$name%"})")
    }

    params.get("category").flatMap(_.headOption).foreach { category =>
      query = concat(query, sql" AND category = $category")
    }

    params.get("min_price").flatMap(_.headOption).flatMap(toBigDecimalOption).foreach { minPrice =>
      query = concat(query, sql" AND price >= $minPrice")
    }

    params.get("max_price").flatMap(_.headOption).flatMap(toBigDecimalOption).foreach { maxPrice =>
      query = concat(query, sql" AND price <= $maxPrice")
    }

    params.get("in_stock").flatMap(_.headOption).flatMap(toBooleanOption).foreach { inStock =>
      query = concat(query, sql" AND in_stock = $inStock")
    }

    params.get("description").flatMap(_.headOption).foreach { desc =>
      query = concat(query, sql" AND LOWER(description) LIKE LOWER(${s"%$desc%"})")
    }

    val sortColumn = params.get("sort_by").flatMap(_.headOption).getOrElse("id")
    val sortDirection = params.get("sort_dir").flatMap(_.headOption).getOrElse("asc")

    // For ORDER BY, we whitelist allowed column names since they can't be parameterized
    val allowedSortColumns = Set("id", "name", "price", "category", "in_stock")
    val safeSortColumn = if (allowedSortColumns.contains(sortColumn)) sortColumn else "id"
    val safeSortDirection = if (sortDirection.equalsIgnoreCase("desc")) "DESC" else "ASC"

    // This is safe because we're using whitelisted values, not user input directly
    val orderClause = (safeSortColumn, safeSortDirection) match {
      case ("name", "ASC")      => sql" ORDER BY name ASC"
      case ("name", "DESC")     => sql" ORDER BY name DESC"
      case ("price", "ASC")     => sql" ORDER BY price ASC"
      case ("price", "DESC")    => sql" ORDER BY price DESC"
      case ("category", "ASC")  => sql" ORDER BY category ASC"
      case ("category", "DESC") => sql" ORDER BY category DESC"
      case ("in_stock", "ASC")  => sql" ORDER BY in_stock ASC"
      case ("in_stock", "DESC") => sql" ORDER BY in_stock DESC"
      case (_, "DESC")          => sql" ORDER BY id DESC"
      case _                    => sql" ORDER BY id ASC"
    }

    query = concat(query, orderClause)

    val limit = params.get("limit").flatMap(_.headOption).flatMap(toIntOption).map(_.min(100).max(1)).getOrElse(20)
    val offset = params.get("offset").flatMap(_.headOption).flatMap(toIntOption).map(_.max(0)).getOrElse(0)

    query = concat(query, sql" LIMIT $limit OFFSET $offset")

    query
  }

  /**
