  private def concat(a: SQLActionBuilder, b: SQLActionBuilder): SQLActionBuilder = {
    SQLActionBuilder(a.queryParts ++ b.queryParts, new SetParameter[Unit] {
      def apply(p: Unit, pp: slick.jdbc.PositionedParameters): Unit = {
        a.unitPConv.apply(p, pp)
        b.unitPConv.apply(p, pp)
      }
    })
  }

  private def toBigDecimalOption(s: String): Option[BigDecimal] =
    try Some(BigDecimal(s)) catch { case _: NumberFormatException => None }

  private def toBooleanOption(s: String): Option[Boolean] =
    s.toLowerCase match {
      case "true" | "1" | "yes"   => Some(true)
      case "false" | "0" | "no"   => Some(false)
      case _                       => None
    }

  private def toIntOption(s: String): Option[Int] =
    try Some(s.toInt) catch { case _: NumberFormatException => None }
}


@Singleton
class ProductSearchController @Inject()(
  val controllerComponents: ControllerComponents,
  protected val dbConfigProvider: DatabaseConfigProvider
)(implicit ec: ExecutionContext)
  extends BaseController
  with HasDatabaseConfigProvider[JdbcProfile] {

  private val queryBuilder = new SecureProductQueryBuilder()

  /**
   * GET /api/products/search?name=...&category=...&min_price=...&max_price=...&in_stock=...&description=...&sort_by=...&sort_dir=...&limit=...&offset=...
   */
  def search(): Action[AnyContent] = Action.async { implicit request =>
    val params = request.queryString

    val query = queryBuilder.buildSearchQuery(params)

    val dbAction = query.as[Product](Product.getResult)

    db.run(dbAction).map { products =>
      Ok(Json.obj(
        "results" -> Json.toJson(products),
        "count" -> products.length,
        "params" -> Json.toJson(params.map { case (k, v) => k -> v.mkString(",") })
      ))
    }.recover {
      case ex: Exception =>
        InternalServerError(Json.obj(
          "error" -> "An error occurred while searching products",
          "message" -> ex.getMessage
        ))
    }
  }

  /**
   * GET /api/products/:id
   */
  def getById(id: Long): Action[AnyContent] = Action.async { implicit request =>
    import profile.api._

    val query = sql"SELECT id, name, description, category, price, in_stock FROM products WHERE id = $id".as[Product](Product.getResult)

    db.run(query.headOption).map {
      case Some(product) => Ok(Json.toJson(product))
      case None          => NotFound(Json.obj("error" -> s"Product with id $id not found"))
    }.recover {
      case ex: Exception =>
        InternalServerError(Json.obj("error" -> ex.getMessage))
    }
  }

  /**
   * GET /api/products/categories
   */
  def listCategories(): Action[AnyContent] = Action.async { implicit request =>
    import profile.api._

    val query = sql"SELECT DISTINCT category FROM products WHERE category IS NOT NULL ORDER BY category ASC".as[String]

    db.run(query).map { categories =>
      Ok(Json.obj("categories" -> categories))
    }.recover {
      case ex: Exception =>
        InternalServerError(Json.obj("error" -> ex.getMessage))
    }
  }
}


